    var popUpNotification = $(""#WSNotification"").data(""kendoNotification"");

    $('#AlhajjMasterForm').submit(function (e) {

        e.preventDefault();
        if ($(""#NIC"").val() == 'لايوجد') {
            $(""#NIC"").addClass(""border border-danger"");
        }

        $.ajax({
            url: this.action,    //Url.Action(""GetAlhajjDataFormWebService"", ""AlhajjMasters"")
            type: this.method,
            data: $(this).serialize(),  // { ServiceNumber: $(""#ServiceNumber"").val() }
